class Book:
    def __init__(self, title, pages):
        self.title = title
        self.pages = pages
    def __str__(self):
        return f'{self.title} ({self.pages} pages)'
    def __lt__(self, other):
        return self.pages < other.pages
b1 = Book('Python 101', 300)
b2 = Book('Deep Learning', 800)
assert str(b1) == 'Python 101 (300 pages)'
assert b1 < b2

class Bag:
    def __init__(self):
        self.items = []
    def add(self, item):
        self.items.append(item)
    def __len__(self):
        return len(self.items)
    def __contains__(self, item):
        return item in self.items
b = Bag()
b.add('apple'); b.add('banana'); b.add('cherry')
assert len(b) == 3
assert 'banana' in b
assert 'grape' not in b
